const rows = $input.all();
const now = new Date();
const today = now.toISOString().split('T')[0];
const yest = new Date(now);
yest.setDate(yest.getDate() - 1);
const yesterdayStr = yest.toISOString().split('T')[0];

let personalToday = 0, businessToday = 0;
let totalYesterday = 0;
let countToday = 0;
const catTotals = {};
const topItems = [];

for (const row of rows) {
  const r = row.json;
  if (!r.Amount) continue;
  const amt = parseFloat(r.Amount) || 0;
  if (amt <= 0) continue;

  if (r.Date === today) {
    if (r.Type === 'Business') businessToday += amt;
    else personalToday += amt;
    countToday++;
    catTotals[r.Category] = (catTotals[r.Category] || 0) + amt;
    topItems.push(`• ${r.Merchant} ₹${amt.toFixed(0)} (${r.Category})`);
  } else if (r.Date === yesterdayStr) {
    totalYesterday += amt;
  }
}

const totalToday = personalToday + businessToday;

// Yesterday comparison
let comparison = '';
if (totalYesterday > 0) {
  const diff = totalToday - totalYesterday;
  const pct = Math.round(Math.abs(diff / totalYesterday) * 100);
  const arrow = diff >= 0 ? '\u2191' : '\u2193';
  comparison = `\nvs yesterday ₹${totalYesterday.toFixed(0)} (${arrow}${pct}%)`;
}

// Monthly running total
const thisMonth = now.getMonth();
const thisYear = now.getFullYear();
let monthTotal = 0;
for (const row of rows) {
  const r = row.json;
  if (!r.Date || !r.Amount) continue;
  const d = new Date(r.Date);
  if (d.getMonth() === thisMonth && d.getFullYear() === thisYear) {
    monthTotal += parseFloat(r.Amount) || 0;
  }
}
const monthName = now.toLocaleString('en-IN', { month: 'long' });

let msg;
if (countToday === 0) {
  const noSpend = totalYesterday > 0 ? `\nYesterday: ₹${totalYesterday.toFixed(0)}` : '';
  msg = `\uD83D\uDCCA *Daily Summary — ${today}*\n\n\u2705 No expenses today!${noSpend}\n\n${monthName} total so far: ₹${monthTotal.toFixed(0)}`;
} else {
  const itemLines = topItems.slice(0, 5).join('\n');
  const moreNote = topItems.length > 5 ? `\n_...and ${topItems.length - 5} more_` : '';
  msg = `\uD83D\uDCCA *Daily Summary — ${today}*\n\n${countToday} expense(s)\n\uD83D\uDC64 Personal: ₹${personalToday.toFixed(0)}\n\uD83D\uDCBC Business: ₹${businessToday.toFixed(0)}\n\uD83D\uDCB0 Total: ₹${totalToday.toFixed(0)}${comparison}\n\n*Today:*\n${itemLines}${moreNote}\n\n${monthName} total: ₹${monthTotal.toFixed(0)}`;
}

return [{ json: { message: msg } }];
